         let dir = tempfile::TempDir::new().unwrap();
         let config = make_minimal_config(&dir);
         let group = make_minimal_group_no_owner(&dir);
         let result = execute_hook("/nonexistent/command_xyz_123", &config, &group);
         assert!(result.is_err());
