For the `check_security_needed` function:
```rust
fn check_security_needed(config: &ResolvedConfig) -> Vec<bool> {
    if !is_root() {
        return vec![false; config.sync_groups.len()];
    }

    if config_owned_by_root(&config.config_path) {
        return vec![false; config.sync_groups.len()];
    }

    config.sync_groups.iter().map(|group| {
        target_dir_owned_by_root(&group.target_dir)
    }).collect()
}

fn target_dir_owned_by_root(target_dir: &Path) -> bool {
    use std::os::unix::fs::MetadataExt;
    match std::fs::metadata(target_dir) {
        Ok(m) => m.uid() == 0,
        Err(_) => false,
    }
}
```

