fn security_prompt(rel_path: &str, accept_all: &mut bool) -> Result<bool, String> {
    if *accept_all {
        return Ok(true);
    }

    use std::io::Write;

    eprint!(
        "\nSecurity: sync '{}' to root-owned target? [y]es [n]o [a]ll [q]uit: ",
        rel_path
    );
    std::io::stderr()
        .flush()
        .map_err(|e| format!("flush: {}", e))?;

    let mut input = String::new();
    std::io::stdin()
        .read_line(&mut input)
        .map_err(|e| format!("read: {}", e))?;

    match input.trim().to_lowercase().as_str() {
        "a" => {
            *accept_all = true;
            Ok(true)
        }
        "y" => Ok(true),
        "q" => Err("Aborted by user due to security confirmation.".to_string()),
        _ => Ok(false),
    }
}

