import { assertEquals, deindent, runningOutsideDocker } from "./lib/index.ts";
import { TestBed } from "./lib/TestBed.ts";
import { getTestDir } from "./lib/setupTestDir.ts";

async function chownTargetToRoot(testDir: URL) {
  const targetDir = new URL("target/", testDir);
  const cmd = new Deno.Command("sudo", {
    args: ["chown", "root:root", targetDir.pathname],
    stdout: "null",
    stderr: "null",
  });
  await cmd.output();
}

async function cleanupTestDir(testDir: URL) {
  const cmd = new Deno.Command("sudo", {
    args: ["rm", "-rf", testDir.pathname],
    stdout: "null",
    stderr: "null",
  });
  await cmd.output();
}

Deno.test({
  name: "security-root-target-confirm-yes",
  ignore: runningOutsideDocker,
}, async (t) => {
  const testDir = getTestDir(t);
  const testbed = await TestBed.create(t, {
    configToml: deindent`
      [[sync]]
      source = "./source"
      target = "./target"
      globs = ["**/*.txt"]
    `,
    files: [
      "user:user | 0755  | config.toml | __CONFIG_TOML__",
      "user:user | 0755  | source/",
      "user:user | 0644  | source/file.txt | source content",
      "user:user | 0755  | target/",
    ],
  });

  try {
    await chownTargetToRoot(testDir);

    const child = testbed.spawn({
      args: ["--config", "config.toml", "sync"],
      sudo: true,
    });

    await child.waitForStderr(
      /Security notice: running as root/,
    );
    await child.waitForStderr(
      /Security: sync 'file\.txt' to root-owned target/,
    );
    await child.type("y\n");
    const { code, stdout } = await child.waitForExit();

    assertEquals(
      stdout,
      "copied file.txt -> target\n\nsource -> target: 1\n" +
        "target -> source: 0\ndeleted target:   0\ndeleted source:   0\n",
    );
    assertEquals(code, 0);
  } finally {
    await cleanupTestDir(testDir);
  }
});

Deno.test({
  name: "security-root-target-confirm-no",
  ignore: runningOutsideDocker,
}, async (t) => {
  const testDir = getTestDir(t);
  const testbed = await TestBed.create(t, {
    configToml: deindent`
      [[sync]]
      source = "./source"
      target = "./target"
      globs = ["**/*.txt"]
    `,
    files: [
      "user:user | 0755  | config.toml | __CONFIG_TOML__",
      "user:user | 0755  | source/",
      "user:user | 0644  | source/file.txt | source content",
      "user:user | 0755  | target/",
    ],
  });

  try {
    await chownTargetToRoot(testDir);

    const child = testbed.spawn({
      args: ["--config", "config.toml", "sync"],
      sudo: true,
    });

    await child.waitForStderr(
      /Security notice: running as root/,
    );
    await child.waitForStderr(
      /Security: sync 'file\.txt' to root-owned target/,
    );
    await child.type("n\n");
    const { code, stdout } = await child.waitForExit();

    assertEquals(
      stdout,
      "skipped (security): file.txt\n\nsource -> target: 0\n" +
        "target -> source: 0\ndeleted target:   0\ndeleted source:   0\n" +
        "permission skips: 1\n",
    );
    assertEquals(code, 0);
  } finally {
    await cleanupTestDir(testDir);
  }
});

Deno.test({
  name: "security-root-target-confirm-all",
  ignore: runningOutsideDocker,
}, async (t) => {
  const testDir = getTestDir(t);
  const testbed = await TestBed.create(t, {
    configToml: deindent`
      [[sync]]
      source = "./source"
      target = "./target"
      globs = ["**/*.txt"]
    `,
    files: [
      "user:user | 0755  | config.toml | __CONFIG_TOML__",
      "user:user | 0755  | source/",
      "user:user | 0644  | source/a.txt | content a",
      "user:user | 0644  | source/b.txt | content b",
      "user:user | 0755  | target/",
    ],
  });

  try {
    await chownTargetToRoot(testDir);

    const child = testbed.spawn({
      args: ["--config", "config.toml", "sync"],
      sudo: true,
    });

    await child.waitForStderr(
      /Security notice: running as root/,
    );
    // Type 'a' on the first prompt - should accept all
    await child.waitForStderr(
      /Security: sync 'a\.txt' to root-owned target/,
    );
    await child.type("a\n");
    const { code, stdout } = await child.waitForExit();

    assertEquals(
      stdout,
      "copied a.txt -> target\ncopied b.txt -> target\n\n" +
        "source -> target: 2\n" +
        "target -> source: 0\ndeleted target:   0\ndeleted source:   0\n",
    );
    assertEquals(code, 0);
  } finally {
    await cleanupTestDir(testDir);
  }
});

Deno.test({
  name: "security-root-target-confirm-quit",
  ignore: runningOutsideDocker,
}, async (t) => {
  const testDir = getTestDir(t);
  const testbed = await TestBed.create(t, {
    configToml: deindent`
      [[sync]]
      source = "./source"
      target = "./target"
      globs = ["**/*.txt"]
    `,
    files: [
      "user:user | 0755  | config.toml | __CONFIG_TOML__",
      "user:user | 0755  | source/",
      "user:user | 0644  | source/a.txt | content a",
      "user:user | 0644  | source/b.txt | content b",
      "user:user | 0755  | target/",
    ],
  });

  try {
    await chownTargetToRoot(testDir);

    const child = testbed.spawn({
      args: ["--config", "config.toml", "sync"],
      sudo: true,
    });

    await child.waitForStderr(
      /Security notice: running as root/,
    );
    await child.waitForStderr(
      /Security: sync 'a\.txt' to root-owned target/,
    );
    await child.type("q\n");
    const { code, stderr } = await child.waitForExit();

    assertEquals(code, 1);
    assertEquals(
      stderr,
      "Security notice: running as root with a config file not owned by root.\n" +
        "Syncing to root-owned target directories requires confirmation for each operation.\n" +
        "\nSecurity: sync 'a.txt' to root-owned target? [y]es [n]o [a]ll [q]uit: " +
        "Error: Aborted by user due to security confirmation.",
    );
  } finally {
    await cleanupTestDir(testDir);
  }
});

Deno.test({
  name: "security-root-target-not-triggered-when-config-owned-by-root",
  ignore: runningOutsideDocker,
}, async (t) => {
  const testDir = getTestDir(t);
  const testbed = await TestBed.create(t, {
    configToml: deindent`
      [[sync]]
      source = "./source"
      target = "./target"
      globs = ["**/*.txt"]
    `,
    files: [
      "root:root | 0755  | config.toml | __CONFIG_TOML__",
      "user:user | 0755  | source/",
      "user:user | 0644  | source/file.txt | source content",
      "user:user | 0755  | target/",
    ],
  });

  try {
    // Chown config.toml to root (since setupTestDir can't do it as non-root)
    const configPath = new URL("config.toml", testDir);
    const chownCmd = new Deno.Command("sudo", {
      args: ["chown", "root:root", configPath.pathname],
      stdout: "null",
      stderr: "null",
    });
    await chownCmd.output();

    // Chown target to root
    await chownTargetToRoot(testDir);

    const child = testbed.spawn({
      args: ["--config", "config.toml", "sync"],
      sudo: true,
    });

    // No security prompt because config is root-owned
    const { code, stdout, stderr } = await child.waitForExit();

    assertEquals(
      stdout,
      "copied file.txt -> target\n\nsource -> target: 1\n" +
        "target -> source: 0\ndeleted target:   0\ndeleted source:   0\n",
    );
    assertEquals(stderr, "");
    assertEquals(code, 0);
  } finally {
    await cleanupTestDir(testDir);
  }
});

Deno.test({
  name: "security-root-target-not-triggered-when-non-root",
}, async (t) => {
  const testDir = getTestDir(t);
  const testbed = await TestBed.create(t, {
    configToml: deindent`
      [[sync]]
      source = "./source"
      target = "./target"
      globs = ["**/*.txt"]
    `,
    files: [
      "user:user | 0755  | config.toml | __CONFIG_TOML__",
      "user:user | 0755  | source/",
      "user:user | 0644  | source/file.txt | source content",
      "user:user | 0755  | target/",
    ],
  });

  // Run as non-root (no sudo) - security check should not trigger
  await testbed.run({ args: ["--config", "config.toml", "sync"] });

  testbed.assertOutput({
    code: 0,
    stdout: deindent`
      copied file.txt -> target

      source -> target: 1
      target -> source: 0
      deleted target:   0
      deleted source:   0
    `,
    stderr: "",
  });
});

